import cadquery as cq
import random

# Pixelated diamond/rhombus-like shape
random.seed(42)

cell = 1.0
thickness = 1.5

# Build a pixelated diamond shape with random jagged edges
# Grid size
grid_w = 30
grid_h = 16

cells = set()

# Create a diamond/rhombus base shape
cx, cy = grid_w / 2, grid_h / 2
for x in range(grid_w):
    for y in range(grid_h):
        # Diamond inequality scaled
        dx = abs(x - cx) / (grid_w / 2)
        dy = abs(y - cy) / (grid_h / 2)
        if dx + dy <= 0.85:
            cells.add((x, y))

# Add jagged edges - randomly extend or remove edge cells
edge_cells = set()
for (x, y) in list(cells):
    for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
        n = (x + dx, y + dy)
        if n not in cells:
            edge_cells.add(n)

# Randomly add some edge cells
for c in edge_cells:
    if random.random() < 0.4:
        cells.add(c)

# Randomly remove some boundary cells to create jagged look
boundary = set()
for (x, y) in list(cells):
    for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
        if (x + dx, y + dy) not in cells:
            boundary.add((x, y))
            break

for c in list(boundary):
    if random.random() < 0.25:
        cells.discard(c)

# Build the result by unioning boxes
result = cq.Workplane("XY")
for (x, y) in cells:
    result = result.union(
        cq.Workplane("XY")
        .box(cell, cell, thickness)
        .translate((x * cell, y * cell, 0))
    )
